<script>
// Own-line line comment before else; a blank line above it is preserved
if(a){f();}

// c1
else{g();}

// Own-line block comment before else; a blank line above it is preserved
if(a){f();}

/* c2 */
else{g();}

// No blank above the comment: none is added
if(a){f();}
// c3
else{g();}
</script>
